export default {
	data() {
		return {
			isMultiSelect: false,
			searchValue: "",
			scrollBarHeight: 0,
			modalName: null,
			dataList: [],
			pageIndex: 0,
			listTouchStart: 0,
			listTouchDirection: null,
			isFirstLoad: true,
			searchParams: [],
			isLoadMore: false
		};
	},
	onReachBottom() {
		this.searchParams = [];
		this.searchValue = "";
		this.pageIndex = 0;
		this.newShowGetBorrowRequestList();
		uni.stopPullDownRefresh();
	},
	onPullDownRefresh() {
		this.searchParams = [];
		this.searchValue = "";
		this.pageIndex = 0;
		this.newShowGetBorrowRequestList();
	},
	onShow() {
		/* if (!this.isFirstLoad) {
			this.pageIndex = parseInt(this.pageIndex) - 1;
			this.newShowGetBorrowRequestList();
		} */
		if(this.$mbservices.getIsRefresh())
		{
			this.pageIndex = 0; // parseInt(this.pageIndex) - 1;
			this.$mbservices.setIsRefresh(false);
			this.newShowGetBorrowRequestList();
		}
		
		this.isFirstLoad = false;
	},
	onLoad() {

		const query = wx.createSelectorQuery();
		query.select("#_tabBar").boundingClientRect();
		query.selectViewport().scrollOffset();
		var _this = this;
		query.exec(function(res) {
			res[0].top; // #the-id节点的上边界坐标
			res[1].scrollTop; // 显示区域的竖直滚动位置
			_this.scrollBarHeight =
				uni.getSystemInfoSync().screenHeight - _this.CustomBar - res[0].height;
		});

		/*加载数据*/
		this.getBorrowRequestList();
	},
	methods: {
		goDetail(item) {
			uni.navigateTo({
				url: "/pages/ReseFund/rfdetail/rfdetail?data=" + JSON.stringify(item)
			});
		},
		newShowGetBorrowRequestList:async function(params){
			this.pageIndex = parseInt(this.pageIndex) + 1;
			var ajaxJSON = {
				pageIndex: this.pageIndex,
				rowsPerPage: "10",
				type: "Initialize",
				Parameter: {
					Sorts: [{
						FieldName: "DocEntry",
						type: "Descending"
					}],
					LoadChildren: "NoLoad",
					Conditions: [{
						FieldName: "Canceled",
						Operation: "EQUAL",
						ConditionValue: "N",
						Relationship: "AND"
					}]
				}
			};
			if (params != undefined && params.length > 0) {
				params.forEach(item => {
					ajaxJSON.Parameter.Conditions.push(item);
				});
			}
			var _this = this;
			this.$mbservices.Request(
				this.$webapi.getBorrowRequestList,
				"POST",
				ajaxJSON,
				function(ret) {
					console.log(ret);
					if (!ret.data.data) {
						_this.dataList = [];
						uni.showToast({
							title: "查无数据"
						});
						return false;
					}
					var _cacheList=[];
					ret.data.data.forEach(item => {
						item.radchecked = false;
						if (item.ApproveStatus === "Pending") {
							item.AApproveStatus = "待审核";
						}
						if (item.ApproveStatus === "Approved") {
							item.AApproveStatus = "已批准";
						}
						if (item.ApproveStatus === "Rejected") {
							item.AApproveStatus = "已拒绝";
						}
						item.Amount = parseFloat(item.Amount).toFixed(2);
						//_this.dataList.push(item);
						_cacheList.push(item);
					});
					//_this.dataList=_cacheList;
					if (_this.isLoadMore) {
						if (_cacheList.length <= 0) {
							_this.pageIndex = parseInt(_this.pageIndex) - 1;
						}
						_cacheList.forEach(item => {
							_this.dataList.push(item);
						})
					} else {
						_this.dataList = _cacheList;
					}
					console.log("&&&&&&&&&&&&&&&&&&&&&&&777")
					console.log(_this.dataList)
				},
				function(ret) {
					uni.showToast({
						title: ret.errMsg,
						icon: "none",
						success: function() {
							setTimeout(function() {
								uni.navigateBack();
							}, 1000);
						}
					});
				}
			);
		},
		getBorrowRequestList(params) {
			uni.showLoading({
				title: "拼命加载中..."
			});
			this.pageIndex = parseInt(this.pageIndex) + 1;
			var ajaxJSON = {
				pageIndex: this.pageIndex,
				rowsPerPage: "10",
				type: "Initialize",
				Parameter: {
					Sorts: [{
						FieldName: "DocEntry",
						type: "Descending"
					}],
					LoadChildren: "NoLoad",
					Conditions: [{
						FieldName: "Canceled",
						Operation: "EQUAL",
						ConditionValue: "N",
						Relationship: "AND"
					}]
				}
			};
			if (params != undefined && params.length > 0) {
				params.forEach(item => {
					ajaxJSON.Parameter.Conditions.push(item);
				});
			}
			var _this = this;
			this.$mbservices.Request(
				this.$webapi.getBorrowRequestList,
				"POST",
				ajaxJSON,
				function(ret) {
					console.log(ret);
					if (!ret.data.data) {
						_this.dataList = [];
						uni.showToast({
							title: "查无数据"
						});
						return false;
					}
					setTimeout(() => {
						var _cacheList=[];
						ret.data.data.forEach(item => {
							item.radchecked = false;
							if (item.ApproveStatus === "Pending") {
								item.AApproveStatus = "待审核";
							}
							if (item.ApproveStatus === "Approved") {
								item.AApproveStatus = "已批准";
							}
							if (item.ApproveStatus === "Rejected") {
								item.AApproveStatus = "已拒绝";
							}
							item.Amount = parseFloat(item.Amount).toFixed(2);
							//_this.dataList.push(item);
							_cacheList.push(item);
						});
						_this.dataList=_cacheList;
						uni.hideLoading();
					}, 1000);
				},
				function(ret) {
					uni.showToast({
						title: ret.errMsg,
						icon: "none",
						success: function() {
							setTimeout(function() {
								uni.navigateBack();
							}, 1000);
						}
					});
				}
			);
		},
		addWorkOrder() {
			uni.navigateTo({
				url: "/pages/ReseFund/rfform/rfform"
			});
		},
		makeParams() {
			if (this.$mbservices.isEmpty(this.searchValue)) {
				this.searchParams=[];
				return false;
			}
			this.searchParams = [{
					FieldName: "DocEntry",
					Operation: "CONTAIN",
					ConditionValue: this.searchValue,
					Relationship: "OR"
				},
				{
					FieldName: "Remarks",
					Operation: "CONTAIN",
					ConditionValue: this.searchValue,
					Relationship: "OR"
				},
				{
					FieldName: "Amount",
					Operation: "CONTAIN",
					ConditionValue: this.searchValue,
					Relationship: "OR"
				}
			];
		},
		searchInput(e) {
			this.searchValue = e.detail.value;
		},
		doSearch(e) {
			//this.dataList = [];
			this.makeParams();
			this.pageIndex = 0;
			this.getBorrowRequestList(this.searchParams);
		},
		loadMore() {
			if (this.searchValue != undefined && this.searchValue.length > 0) {
				this.makeParams();
			}
			this.isLoadMore = true;
			this.newShowGetBorrowRequestList(this.searchParams);
		},
		// ListTouch触摸开始
		ListTouchStart(indx, e) {
			if (this.dataList[indx].Approve === "Yes"&&(this.dataList[indx].ApproveStatus==='Pending'||this.dataList[indx].ApproveStatus==='Approved')) {
				return false;
			}
			this.listTouchStart = e.touches[0].pageX;
		},

		// ListTouch计算方向
		ListTouchMove(indx, e) {
			if (this.dataList[indx].Approve === "Yes"&&(this.dataList[indx].ApproveStatus==='Pending'||this.dataList[indx].ApproveStatus==='Approved')) {
				return false;
			}
			this.listTouchDirection =
				e.touches[0].pageX - this.listTouchStart > 0 ? "right" : "left";
		},

		// ListTouch计算滚动
		ListTouchEnd(indx, e) {
			if (this.dataList[indx].Approve === "Yes"&&(this.dataList[indx].ApproveStatus==='Pending'||this.dataList[indx].ApproveStatus==='Approved')) {
				return false;
			}
			if (this.listTouchDirection == "left") {
				this.modalName = e.currentTarget.dataset.target;
			} else {
				this.modalName = null;
			}
			this.listTouchDirection = null;
		},
		editItem(item) {
			uni.navigateTo({
				url: "/pages/ReseFund/rfform/rfform?flag=modify&data=" + JSON.stringify(item)
			});
		},
		deleteItem(item) {
			this.modalName = null;
			var _this = this;
			uni.showModal({
				title: "操作提示",
				content: "确定删除选中项?",
				success(res) {
					if (res.confirm) {
						item.UIStatus = "Delete";
						item.Canceled = "Yes";
						_this.$mbservices.Request(
							_this.$webapi.submitBorrowRequest,
							"POST",
							item,
							function(succ) {
								console.log(succ);
								if (succ.statusCode === 200) {
									var cache = [];
									_this.dataList.forEach(_item => {
										if (_item != item) {
											cache.push(_item);
										}
									});
									_this.dataList = [];
									cache.forEach(_item => {
										_this.dataList.push(_item);
									});
								}
							},
							function(err) {
								console.log(err);
							}
						);
					}
				}
			});
		}
	}
};
